import java.util.regex.Matcher;
import java.util.function.Function;
import java.util.Optional;
import java.util.Collections;

public class Main {
    public static void main(String[] args) throws IOException {
        Scanner sc = new Scanner(System.in);
        List<String> lines = new ArrayList<>();
        Map<String, Integer> counts = new HashMap<>();
        Set<String> unique = new HashSet<>();

        while (sc.hasNextLine()) {
            String line = sc.nextLine();
            if (line.isEmpty()) break;
            lines.add(line);
            unique.add(line);
            counts.merge(line, 1, Integer::sum);
        }

        LocalDate today = LocalDate.now();
        DateTimeFormatter fmt = DateTimeFormatter.ISO_LOCAL_DATE;
        String dateStr = today.format(fmt);

        Function<String, String> trim = String::trim;
        List<String> trimmed = lines.stream().map(trim).collect(Collectors.toList());

        Pattern p = Pattern.compile("\\w+");
        Optional<String> first = trimmed.stream().findFirst();
        first.ifPresent(s -> {
            Matcher m = p.matcher(s);
            if (m.find()) System.out.println("First word: " + m.group());
        });

        System.out.println("Date: " + dateStr);
        System.out.println("Lines: " + lines.size());
        System.out.println("Unique: " + unique.size());
        System.out.println("Counts: " + counts);
    }
