 "source": "import * as fs from 'fs';

function printFibonacci(n: number): void {
    if (n <= 0) return;
    if (n === 1) {
        console.log(0);
        return;
    }
    const fib: number[] = [0, 1];
    for (let i = 2; i < n; i++) {
        fib.push(fib[i - 1] + fib[i - 2]);
    }
    console.log(fib.join(" "));
}

function main(): void {
    const input: string = fs.readFileSync(0, 'utf-8').trim();
    const N: number = parseInt(input, 10);
    if (!isNaN(N)) {
        printFibonacci(N);
    }
}

